      rankCorrelationChoice: { area: "Correlación por rangos", question: "¿Qué correlación por rangos desea reportar?", hint: "Spearman es común y fácil de interpretar. Tau de Kendall suele ser más estable con muestras pequeñas o muchos empates.", step: "Selección de prueba", answers: [{ label: "Correlación por rangos de Spearman", result: "spearman" }, { label: "Correlación por rangos de Kendall", result: "kendall" }] },
      comparisonOutcome: { area: "Nivel de medición", question: "¿Qué tipo de variable dependiente tiene?", hint: "Las variables dependientes métricas suelen llevar a pruebas t o ANOVA. Las ordinales necesitan alternativas robustas.", step: "Nivel de medición", answers: [{ label: "Variable dependiente métrica", next: "metricGroups" }, { label: "Variable dependiente ordinal", next: "ordinalGroups" }, { label: "Variable dependiente categórica", next: "categoricalDesign" }, { label: "Observaciones repetidas o agrupadas", next: "mixedModelOutcome" }, { label: "Comparar varianzas", next: "varianceComparison" }] },
