      oneSampleKnownVariance: { area: "Supuesto", question: "¿Se conoce la desviación estándar o la varianza poblacional?", hint: "Una prueba z para una muestra requiere que la dispersión poblacional sea conocida antes del análisis. Si la dispersión se estima a partir de la muestra, normalmente conviene la prueba t.", step: "Supuestos", answers: [{ label: "Sí, la dispersión poblacional es conocida", result: "oneSampleZ" }, { label: "No, la dispersión se estima desde la muestra", next: "oneSampleNormal" }] },
      oneSampleNormal: { area: "Supuesto", question: "¿La variable métrica tiene una distribución aproximadamente normal?", hint: "En muestras pequeñas este supuesto pesa más. En muestras grandes también ayudan las comprobaciones gráficas.", step: "Supuestos", answers: [{ label: "Sí", result: "oneSampleT" }, { label: "No o claramente asimétrica", result: "oneSampleWilcoxon" }] },
