      twoPairedNormal: { area: "Supuesto", question: "¿Las diferencias entre mediciones relacionadas son aproximadamente normales?", hint: "En comparaciones relacionadas importa la distribución de las diferencias.", step: "Supuestos", answers: [{ label: "Sí", result: "pairedT" }, { label: "No u ordinal", result: "wilcoxon" }] },
      manyGroupsDesign: { area: "Diseño de grupos", question: "¿Cuántos factores compara y hay mediciones repetidas?", hint: "Con más de un factor se pueden probar efectos principales e interacciones. Las mediciones repetidas cambian el modelo y los supuestos.", step: "Grupos", answers: [{ label: "Un factor: grupos independientes", next: "anovaAssumptions" }, { label: "Un factor: mediciones repetidas", next: "repeatedAssumptions" }, { label: "Dos o más factores: sin mediciones repetidas", next: "twoWayAnovaAssumptions" }, { label: "Dos o más factores: con mediciones repetidas", next: "twoWayRepeatedAssumptions" }] },
      anovaAssumptions: { area: "Supuesto", question: "¿Son aceptables la normalidad por grupo y la igualdad de varianzas?", hint: "Si se incumplen los supuestos, una alternativa no paramétrica suele ser más robusta.", step: "Supuestos", answers: [{ label: "Sí", result: "anova" }, { label: "No u ordinal", result: "kruskalWallis" }] },
      repeatedAssumptions: { area: "Supuesto", question: "¿Son plausibles las mediciones métricas y la esfericidad?", hint: "Con medidas repetidas pueden necesitarse correcciones como Greenhouse-Geisser.", step: "Supuestos", answers: [{ label: "Sí", result: "repeatedAnova" }, { label: "No u ordinal", result: "friedman" }] },
      twoWayAnovaAssumptions: { area: "Supuesto", question: "¿Son plausibles la normalidad dentro de las celdas, la homogeneidad de varianzas y las observaciones independientes?", hint: "Una ANOVA factorial prueba efectos principales e interacciones para dos o más factores.", step: "Supuestos", answers: [{ label: "Sí", result: "twoWayAnova" }, { label: "No u ordinal", result: "nonparametricTwoWayAnova" }] },
      twoWayRepeatedAssumptions: { area: "Supuesto", question: "¿Son plausibles las mediciones métricas, los supuestos de esfericidad adecuados y un diseño repetido balanceado?", hint: "Con dos o más factores y mediciones repetidas pueden importar los efectos principales, las interacciones y las correcciones de esfericidad.", step: "Supuestos", answers: [{ label: "Sí", result: "twoWayRepeatedAnova" }, { label: "No u ordinal", result: "nonparametricTwoWayRepeatedAnova" }] },
      ordinalGroups: { area: "Diseño de grupos", question: "¿Cómo están organizadas las mediciones ordinales?", hint: "Las alternativas robustas también distinguen entre datos independientes y relacionados.", step: "Grupos", answers: [{ label: "Dos grupos independientes", result: "mannWhitney" }, { label: "Dos mediciones relacionadas", result: "wilcoxon" }, { label: "Varios grupos independientes", result: "kruskalWallis" }, { label: "Varias mediciones relacionadas", result: "friedman" }] },
      categoricalDesign: { area: "Categorías", question: "¿Cómo está estructurada la pregunta categórica?", hint: "Para frecuencias y proporciones importan el número de variables, las frecuencias esperadas y si las observaciones son relacionadas.", step: "Categorías", answers: [{ label: "Dos variables categóricas independientes", result: "chiSquareAssociation" }, { label: "Frecuencias esperadas pequeñas en una tabla 2x2", result: "fisher" }, { label: "Dos mediciones dicotómicas relacionadas", result: "mcnemar" }, { label: "Comparar distribución teórica y empírica para una variable de dos niveles", result: "binomialTest" }, { label: "Comparar distribución teórica y empírica para una variable multinivel", result: "chiSquareGoodness" }] },
      predictionOutcome: { area: "Variable objetivo", question: "¿Qué nivel de medición tiene la variable que desea predecir?", hint: "La variable objetivo determina la familia del modelo. Los predictores pueden ser métricos o codificados como categorías.", step: "Variable objetivo", answers: [{ label: "Variable objetivo métrica", result: "linearRegression" }, { label: "Variable objetivo dicotómica", result: "logisticRegression" }, { label: "Variable objetivo categórica con varias categorías", result: "multinomialRegression" }] }
