      logLinearModel: { title: "Modelo log-lineal", summary: "Modela asociaciones e interacciones entre varias variables nominales en una tabla de contingencia.", assumptions: ["Varias variables nominales", "Datos de frecuencias en una tabla de contingencia", "Observaciones independientes", "Frecuencias esperadas suficientes"] },
