      structuralEquationModeling: { title: "Modelado de ecuaciones estructurales (SEM)", summary: "Combina modelos de medición para variables latentes con rutas estructurales dirigidas entre variables latentes y observadas.", assumptions: ["Constructos latentes medidos por varios indicadores", "Modelo de medición y estructural justificado teóricamente", "Tamaño muestral suficiente", "Evaluar ajuste del modelo y modelos alternativos"] },
      discriminantAnalysis: { title: "Análisis discriminante", summary: "Clasifica casos en grupos nominales a partir de varios predictores de escala de intervalo y describe qué variables separan los grupos.", assumptions: ["Variable dependiente nominal con grupos conocidos", "Variables independientes de escala de intervalo", "Normalidad multivariante dentro de los grupos", "Matrices de covarianza similares", "Tamaños de grupo suficientes"] },
      oneSampleT: { title: "Prueba t para una muestra", summary: "Compara la media de una muestra métrica con un valor de referencia.", assumptions: ["Variable métrica", "Observaciones independientes", "Distribución aproximadamente normal"] },
      oneSampleZ: { title: "Prueba z para una muestra", summary: "Compara la media de una muestra métrica con un valor de referencia cuando se conoce la desviación estándar o la varianza poblacional.", assumptions: ["Variable métrica", "Observaciones independientes", "Desviación estándar o varianza poblacional conocida", "Población normal o muestra suficientemente grande"] },
      oneSampleWilcoxon: { title: "Prueba de Wilcoxon para una muestra", summary: "Alternativa no paramétrica cuando se compara una mediana o patrón de rangos con una referencia.", assumptions: ["Datos al menos ordinales", "Diferencias simétricas útiles", "Observaciones independientes"] },
      independentT: { title: "Prueba t para muestras independientes", summary: "Compara las medias de dos grupos independientes con una variable dependiente métrica.", assumptions: ["Dos grupos independientes", "Variable dependiente métrica", "Normalidad aproximada", "Varianzas iguales o corrección de Welch"] },
      mannWhitney: { title: "Prueba U de Mann-Whitney", summary: "Alternativa no paramétrica a la prueba t independiente para dos grupos independientes.", assumptions: ["Dos grupos independientes", "Variable al menos ordinal", "Formas de distribución similares para interpretar localización"] },
      pairedT: { title: "Prueba t para muestras relacionadas", summary: "Compara dos medias relacionadas, por ejemplo mediciones antes-después.", assumptions: ["Dos mediciones relacionadas", "Diferencias métricas", "Normalidad aproximada de las diferencias"] },
      wilcoxon: { title: "Prueba de rangos con signo de Wilcoxon", summary: "Opción no paramétrica para dos mediciones relacionadas o comparaciones ordinales relacionadas.", assumptions: ["Dos mediciones relacionadas", "Valores al menos ordinales", "Emparejamiento presente"] },
      anova: { title: "ANOVA de un factor", summary: "Compara medias de más de dos grupos independientes.", assumptions: ["Grupos independientes", "Variable dependiente métrica", "Normalidad por grupo", "Homogeneidad de varianzas"] },
      repeatedAnova: { title: "ANOVA de medidas repetidas", summary: "Prueba diferencias de medias en varios momentos o condiciones relacionados.", assumptions: ["Mediciones repetidas", "Variable dependiente métrica", "Esfericidad o corrección adecuada"] },
      twoWayAnova: { title: "ANOVA factorial (dos o más factores)", summary: "Prueba efectos principales e interacciones de dos o más factores independientes sobre una variable dependiente métrica.", assumptions: ["Dos o más factores independientes categóricos", "Variable dependiente métrica", "Observaciones independientes", "Normalidad dentro de las celdas", "Homogeneidad de varianzas"] },
      twoWayRepeatedAnova: { title: "ANOVA factorial con medidas repetidas (dos o más factores)", summary: "Prueba efectos principales e interacciones de dos o más factores cuando al menos un factor se mide en los mismos participantes.", assumptions: ["Al menos un factor de medidas repetidas", "Variable dependiente métrica", "Esfericidad o corrección adecuada", "Asignación balanceada de momentos o condiciones"] },
      linearMixedModel: { title: "Modelo lineal mixto", summary: "Modela variables dependientes métricas en observaciones repetidas, anidadas o agrupadas con efectos fijos y aleatorios.", assumptions: ["Variable dependiente métrica", "Observaciones anidadas en personas, equipos o momentos de medición", "Efectos aleatorios justificados teóricamente", "Revisar diagnósticos de residuos y estructura de varianza"] },
      generalizedLinearMixedModel: { title: "Modelo lineal generalizado mixto", summary: "Extiende modelos logísticos u otros modelos generalizados a datos repetidos, anidados o agrupados.", assumptions: ["Variable dependiente dicotómica, categórica o de conteo", "Función de enlace y distribución adecuadas", "Clusters o personas como efectos aleatorios", "Eventos suficientes por parámetro"] },
      ordinalMixedModel: { title: "Modelo mixto ordinal", summary: "Modela variables dependientes ordinales con observaciones repetidas o agrupadas, a menudo mediante modelos de enlace acumulativo.", assumptions: ["Variable dependiente ordinal", "Observaciones repetidas o agrupadas", "Comprobar supuesto de odds proporcionales", "Efectos aleatorios justificados teóricamente"] },
      kruskalWallis: { title: "Prueba de Kruskal-Wallis", summary: "Alternativa no paramétrica al ANOVA de un factor para varios grupos independientes.", assumptions: ["Varios grupos independientes", "Variable al menos ordinal", "Observaciones independientes"] },
      friedman: { title: "Prueba de Friedman", summary: "Alternativa no paramétrica al ANOVA de medidas repetidas para varias condiciones relacionadas.", assumptions: ["Varias mediciones relacionadas", "Valores al menos ordinales", "Los mismos casos en todas las condiciones"] },
      nonparametricTwoWayAnova: { title: "ANOVA factorial no paramétrica (ART)", summary: "Alternativa robusta para diseños factoriales con dos o más factores independientes, habitualmente mediante transformación de rangos alineados.", assumptions: ["Dos o más factores independientes categóricos", "Variable al menos ordinal", "Observaciones independientes", "Interacciones probadas con datos transformados en rangos"] },
      nonparametricTwoWayRepeatedAnova: { title: "ANOVA factorial no paramétrica con medidas repetidas (ART)", summary: "Alternativa robusta para diseños repetidos factoriales con dos o más factores cuando los supuestos paramétricos no son sostenibles.", assumptions: ["Al menos un factor de medidas repetidas", "Variable al menos ordinal", "Los mismos casos en condiciones relacionadas", "Interacciones probadas con datos transformados en rangos"] },
      fisher: { title: "Prueba exacta de Fisher", summary: "Prueba asociaciones en tablas 2x2 pequeñas cuando no se cumplen los supuestos de chi-cuadrado.", assumptions: ["Variables categóricas dicotómicas", "Observaciones independientes", "Frecuencias esperadas pequeñas"] },
      mcnemar: { title: "Prueba de McNemar", summary: "Compara dos mediciones dicotómicas relacionadas, como categorías antes-después.", assumptions: ["Dos mediciones dicotómicas relacionadas", "Datos emparejados", "Pares discordantes relevantes"] },
      binomialTest: { title: "Prueba binomial", summary: "Prueba si la frecuencia o proporción empírica de una variable de dos niveles difiere de una probabilidad teórica esperada.", assumptions: ["Variable categórica de dos niveles", "Proporción teórica esperada definida", "Observaciones independientes", "Número fijo de ensayos o casos"] },
